import{_ as a,o as p,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"行刑官","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/社交类/行刑官.md","filePath":"4.资源分区/6.技艺及称号/社交类/行刑官.md"}'),s={name:"4.资源分区/6.技艺及称号/社交类/行刑官.md"};function o(d,e,l,_,i,c){return p(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"行刑官",tabindex:"-1"},[b("行刑官 "),r("a",{class:"header-anchor",href:"#行刑官","aria-label":'Permalink to "行刑官"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"汹涌疾风023")])])],-1),n('<h1 id="行刑官-1" tabindex="-1">行刑官 <a class="header-anchor" href="#行刑官-1" aria-label="Permalink to &quot;行刑官&quot;">​</a></h1><p>行刑官</p><p>所谓行刑官，便是黑暗帝国的一种特殊的官僚，他们作为黑暗帝国在宣传方面的招牌杀器，让帝国的敌人心惊胆寒。一般而言，行刑官会在帝国的宣传直播或是战场前线上进行行刑表演，以华丽而残忍的手段提振己方士气，同时使敌人畏惧。</p><p>D+1500<br> 行刑官学徒</p><p>想要学习行刑，就要从杀人和审讯开始，无论是哪种行刑风格，都离不开奠基的过程。<br> 行刑官学徒需要先系统性的完成两项考核，并在完成考核的过程中增进自己的杀戮和审讯技巧。如果完成不了考核，就会自然在考核中被淘汰。</p><p>两项考核中的每一项的前提均为表现分达到【传说】，并在那场影片结束后视为完成考核，在完成考核后，每次达到杀戮考核要求的影片结束后，就会再获得一次杀戮考核奖励。</p><p>杀戮<br> 前提：一场战斗<br> 完成杀戮考核后，在执刑时，所有观看到处刑的符合条件的目标都会额外增加1对抗DC。</p><p>审讯<br> 前提：一场审讯<br> 完成审讯考核后，在执刑时，还可以从被执刑者口中得到一条其所知信息，这条信息由ST决定，这视为一个D级创伤来源的解析效果。</p><p>执刑<br> 在行刑官学徒阶段，无论是否通过了考核，都会系统性的学习如何执刑，但由于现阶段行刑官学徒的水平不高，所以只能执刑处于无助状态的敌人，这要求行刑官只能对无助的敌方单位进行仓促执刑。<br> 行刑官立刻使用一个整轮动作，利用手头现有的一切工具和武器对那个无助的敌方单位进行执刑，立即以一连串符合现有情况的处刑步骤，并在处刑结束时将对那个目标进行致命攻击。<br> 若这一单位具有支线等级，则所有观看到这次处刑的支线等级不高于这一单位的敌方单位需通过一个DC为5的意志豁免检定，若检定失败，则立即承受等同于行刑官的传奇风度*2点攻击上的士气减值，这些减值将持续存在一轮。</p><p>C+1000<br> 初级行刑官</p><p>从这一阶段开始，初窥门径的行刑官将开始培养锻炼自己的行刑风格，或模仿，或独创，在残忍的处决敌人的同时，也能提振己方的士气。</p><p>执刑+<br> 在初级行刑官阶段，行刑官已经对行刑愈发熟练，因此只需要一个标准动作就能完成处刑，与此同时，行刑的成果也将因行刑官逐渐纯熟的技术而提升。<br> 用以下效果代替【执刑】效果：<br> 行刑官立刻使用一个标准动作，利用手头现有的一切工具和武器对那个无助的敌方单位进行一次执刑，立即以一连串符合现有情况的处刑步骤，并在处刑结束时将对那个目标进行致命攻击。<br> 若这一单位具有支线等级，则所有观看到这次处刑的支线等级不高于这一单位的敌方单位需通过一个DC为10的意志豁免检定，若检定失败，则立即承受等同于行刑官的传奇风度*3点攻击上的士气减值。而所有观看到这次处刑的友方单位将立即获得等同于行刑官的传奇风度*2点攻击上的士气加值，这些减/加值将持续存在一轮。</p><p>摸索风格<br> 在成为初级行刑官后，经过一场执刑过的影片后，行刑官将初步摸索出自己的行刑风格，从下列风格中选择一种，此后不能更改。</p><p>精密切割/千刀万剐<br> 如果两只手不够把肉货切成艺术品，就多搞几只。——“机械师”<br> 现在，阿修罗2级可以被应用于执刑之中，效果变为每有一只手参与到执刑之中，这次执刑的意志豁免对抗就增加1点DC。<br> 现在，当执刑时，若已拥有【黑暗艺术】，则可以不将被执刑的对象立即杀死，但执刑的后续效果还是会在那一轮正常结算，执刑的对象立即获得等同于其生命上限*2的流血点数，这是一个A级创伤来源的即死效果。<br> 被执刑的对象因此法获得的流血点数而死亡时，将再结算一次执刑的效果。</p><p>恐惧之源/不灭梦魇<br> “想试一次吗？保证终身难忘，但很可惜，一个人只能试一次。”——“巴力”秦虹<br> 现在，高山阵地2级可以被应用于执刑之中，效果变为被执刑者的尸体周围将产生半径为5M的D级困难地形。<br> 现在，当执刑时，若已拥有【唯我独尊】，则此后执刑官的传奇风度能力将改为在执刑时，所有观察到执刑的敌方单位将承受持续一轮的1点全检定减值。<br> 被以此法而承受全检定减值的敌人将再额外承受等同于行刑官传奇风度*1点不可豁免的恐惧点数。</p><p>万众狂欢/华丽表演<br> “欢呼吧，庆贺吧，狂舞吧，然后，死吧。”<br> ——“人偶师”诺艾尔·奥丁森<br> 现在观看你执刑的单位进行的意志豁免DC提升三分之一。<br> 现在，当执刑时，若已拥有【灵性共鸣】，则仅限于行刑的那一轮，被行刑者可以被视为满足【灵性共鸣】的应用目标。</p><p>B+2000<br> 高阶行刑官</p><p>现在，行刑已经对高阶行刑官而言如同家常便饭，如呼吸一般自然。</p><p>执刑++<br> 用以下效果代替【执刑+】<br> 行刑官立刻使用一个标准动作，利用手头现有的一切工具和武器对那个无助的敌方单位进行一次执刑，立即以一连串符合现有情况的处刑步骤，并在处刑结束时对那个目标进行致命攻击。<br> 若这一单位具有支线等级，所有观看到这次处刑的支线等级不高于这一单位的敌方单位需通过一个DC为16的意志豁免检定，若检定失败，则立即承受等同于行刑官的传奇风度*8点攻击上的士气减值。而所有观看到这次处刑的友方单位将立即获得等同于行刑官的传奇风度*8点攻击上的士气加值，这些减/加值将持续存在一轮。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const D=a(s,[["render",o]]);export{f as __pageData,D as default};
